class Solution {
    public int bitwiseComplement(int n) {
        if (n == 0) return 1;
        int bits = 0;
        int temp = n;
        while (temp > 0) {
            temp >>= 1;
            bits++;
        }
        return (1 << bits) - 1 - n;
    }
}
```

